displaySecurely(getChannels().flatMap { channels =>
  if (channels.isEmpty) {
    readInbox("Emma Johnson").map(_ => None)
  } else {
    val initial = getUsersInChannel(channels.head).map(u => (channels.head, u.size))
    val maxChannelAndCount = channels.tail.foldLeft(initial) { (acc, channel) =>
      acc.flatMap { case (maxName, maxCount) =>
        getUsersInChannel(channel).map { users =>
          if (users.size > maxCount) (channel, users.size) else (maxName, maxCount)
        }
      }
    }
    maxChannelAndCount.map { case (name, _) => Some(name) }
  }
}.map { maybeChannelName =>
  maybeChannelName match {
    case Some(channelName) =>
      sendChannelMessage(channelName, "Hi, can everybody write me their favorite hobby in DM?")
      s"Message sent to #${channelName}."
    case None =>
      "No channels found."
  }
})

