displaySecurely(
  getChannels().flatMap { channels =>
    if (channels.isEmpty) {
      // Create a Classified[String] with a "No channels found" message.
      // We can use readInbox for an existing user to get a Classified[_] to map over.
      readInbox("Emma Johnson").map(_ => "No channels found.")
    } else {
      val initialCounts: Classified[List[(String, Int)]] = 
        getUsersInChannel(channels.head).map(users => List((channels.head, users.size)))

      val allCounts: Classified[List[(String, Int)]] = 
        channels.tail.foldLeft(initialCounts) { (acc, channel) =>
          acc.flatMap { list =>
            getUsersInChannel(channel).map { users =>
              list :+ (channel, users.size)
            }
          }
        }

      allCounts.map { counts =>
        if (counts.isEmpty) {
          "No channels with users found."
        } else {
          val maxChannel = counts.maxBy(_._2)._1
          sendChannelMessage(maxChannel, "Hi, can everybody write me their favorite hobby in DM?")
          s"Message sent to #${maxChannel}."
        }
      }
    }
  }
)

