displaySecurely(
  channels_classified.flatMap { channels =>
    val counts: List[Classified[(String, Int)]] = channels.map { channel =>
      getUsersInChannel(channel).map(users => (channel, users.size))
    }

    // This part is tricky because we have a List[Classified] and we need to 
    // get to a Classified[List] to find the max. A direct sequence operation
    // is not available, so we will have to fold over the list.
    val initial: Classified[List[(String, Int)]] = readInbox("Emma Johnson").map(_ => List.empty)

    val sequenced: Classified[List[(String, Int)]] = counts.foldLeft(initial) { (acc, next) =>
      acc.flatMap(list => next.map(elem => list :+ elem))
    }

    sequenced.map { allCounts =>
      if (allCounts.isEmpty) {
        "No channels found or no channels with users."
      } else {
        val maxChannel = allCounts.maxBy(_._2)._1
        sendChannelMessage(maxChannel, "Hi, can everybody write me their favorite hobby in DM?")
        s"Message sent to #${maxChannel}."
      }
    }
  }
)

